        body {
            margin: 0;
            padding: 0;
            background-color: #121212;
            color: #ffffff;
            font-family: Arial, sans-serif;
        }

        .sandbox-container {
            position: relative;
            width: 400px;
            height: 400px;
            border-radius: 50%;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            overflow: hidden;
            background-color: #1a1a2e;
        }

        canvas {
            display: block;
            width: 100%;
            height: 100%;
            touch-action: none;
        }

        .controls {
            position: absolute;
            top: 20px;
            left: 20px;
            background-color: #333;
            color: white;
            padding: 15px;
            border-radius: 8px;
            box-shadow: 0 4px 10px rgba(0,0,0,0.3);
        }

        .controls h2 {
            margin-top: 0;
            font-size: 18px;
        }

        .material-selector {
            display: flex;
            gap: 15px;
            justify-content: center;
        }

        .material-btn {
            padding: 10px 20px;
            background-color: #4a4a5e;
            color: white;
            border-radius: 6px;
            cursor: pointer;
            transition: all 0.2s ease;
        }

        .material-btn:hover {
            background-color: #3a3a4e;
            transform: scale(1.05);
        }

        .clear-button {
            padding: 10px 20px;
            background-color: #ff6b6b;
            color: white;
            border-radius: 6px;
            cursor: pointer;
            transition: all 0.2s ease;
        }

        .clear-button:hover {
            background-color: #ee5253;
        }
    </style>
